# 
# Examples:
# get_row([
#   [1,2,3,4,5,6],
#   [1,2,3,4,1,6],
#   [1,2,3,4,5,1]
# ], 1) == [(0, 0), (1, 4), (1, 0), (2, 5), (2, 0)]
# get_row([], 1) == []
# get_row([[], [1], [1, 2, 3]], 3) == [(2, 2)]
#
sub get_row
{
  my ($lst, $x) = @_;
  my @rows = map { $_->[0] } @$lst;
  my @cols = map { $_->[1] } @$lst;
  my @res = map {
    my ($row, $col) = @$_;
    ($row, $col) if $row == $x;
  } sort { $a <=> $b } @rows, @cols;
  return @res;
}

