def fib2(n: int):
    """Return n-th Fibonacci number.
    >>> fib2(10)
    55
    >>> fib2(1)
    1
    >>> fib2(8)
    21
    """
    a, b = 0, 1
    for _ in range(n):
        a, b = b, a + b
    return a


