/**
 * Return the factorial of x
 * >>> factorial(5)
 * 120
 * >>> factorial(0)
 * 1
 *
 */
function factorial(x) {
  if (x === 0) {
    return 1;
  }
  return x * factorial(x - 1);
}

/**
 * Return the nth fibonacci number
 * >>> fibonacci(5)
 * 5
 * >>> fibonacci(10)
 * 55
 *
 */
function fibonacci(n) {
  if (n === 0) {
    return 0;
  }
  if (n === 1) {
    return 1;
  }
  return fibonacci(n - 1) + fibonacci(n - 2);
}

