    $m = count($grid[0]);
    $ans = 0;
    for($i = 0; $i < $n; $i++){
        for($j = 0; $j < $m; $j++){
            if($grid[$i][$j] == 1){
                $ans += $capacity;
                $capacity -= $grid[$i][$j];
                $grid[$i][$j] = 0;
            }
        }
    }
    return $ans;
}

