{
  my ($s) = @_;
  my @s = split //, $s;
  my $i = 0;
  my $j = 0;
  my $result = 0;
  while ($i < @s)
  {
    if ($s[$i] eq $s[$j])
    {
      $i++;
      $j++;
    }
    else
    {
      $result = 0;
      last;
    }
  }
  return ($result, 1);
}

