func count_triples (a []int) int {
	var count int
	for i := 0; i < len(a)-2; i++ {
		for j := i + 1; j < len(a)-1; j++ {
			for k := j + 1; k < len(a); k++ {
				if a[i] + a[j] + a[k] % 3 == 0 {
					count++
				}
			}
		}
	}
	return count
}

