func md5 (text string) interface{} {
	// convert to bytes
	bytes := []byte(text)
	// convert to hex
	hex := make([]byte, 0, 32)
	for _, b := range bytes {
		hex = append(hex, byte(b))
	}
	// convert to md5
	md5 := make([]byte, 0, 32)
	for i := 0; i < 32; i++ {
		md5 = append(md5, hex[i])
	}
	return md5
}

