func checkPalindrome(s : String, c : String) -> (String, Bool) {
    var result = reverseDelete(s: s, c: c)
    if result.count == 0 {
        return ("", false)
    }
    return ("".join(result), true)
}

func palindrome(s : String, c : String) -> Bool {
    return checkPalindrome(s: s, c: c).first == "True"
}

