            for (int j = 0; j < m; j++) {
                if (grid.get(i).get(j) == 0) {
                    dp[i][j] = 0;
                } else {
                    dp[i][j] = capacity;
                }
            }
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (grid.get(i).get(j) == 1) {
                    for (int k = 0; k < m; k++) {
                        if (dp[i][k] > 0 && dp[i][k] < dp[i][j]) {
                            dp[i][j] = dp[i][k];
                        }
                    }
                }
            }
        }
        int ans = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (dp[i][j] > 0) {
                    ans++;
                }
            }
        }
        return ans;
    }

