/// For example:
/// >>> OrderByPoints([1, 11, -1, -11, -12]) == [-1, -11, 1, -12, 11]
/// >>> OrderByPoints([]) == []
/// 
/// </summary>
public static List<int> OrderByPoints (List<int> nums, int maxSum, int minSum) 
{ 
    var sorted = nums.OrderBy(x => x).ToList();
    var sum = 0;
    var index = 0;
    foreach (var item in sorted)
    {
        sum += item;
        if (sum > maxSum)
        {
            index++;
            sum = item;
        }
        else if (sum < minSum)
        {
            index--;
            sum = item;
        }
    }
    return sorted.Take(index).ToList();
}

